# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.
# Category: race_condition

import akka.actor.{Actor, ActorLogging, PoisonPill, Props}

case class Deposit(amount: Double)
case class Withdrawal(amount: Double)

class AccountActor extends Actor with ActorLogging {
  var balance: Double = 0

  override def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      log.info(s"Deposited $amount, new balance: $balance")

    case Withdrawal(amount) if availableBalance >= amount =>
      balance -= amount
      log.info(s"Withdrew $amount, new balance: $balance")

    case Withdrawal(amount) =>
      log.warning(s"Insufficient funds (${availableBalance} < $amount). Ignoring request.")

    case _ =>
      log.info("Received unknown message.")
  }

  def availableBalance: Double = balance
}

object AccountActor {
  def props: Props = Props(classOf[AccountActor])
}